#include <iostream>
using namespace std;
int main()
{
    int n, s, a, b;
    int all =0; 
    cin >> n >> s;
    cin >> a >> b;
    int xay[n][2];
    for (int i = 0; i < n; i++)
    {
        for (int j = 0; j < 2; j++)
        {
            cin >> xay[i][j];
        }
    }

    for (int i = n; i > 1; i--)
    {
        for (int j = 0; j < i ; j++)
        {
            int l[2];
            if (xay[j + 1][1] < xay[j][1])
            {
                l[0] = xay[j][0];
                l[1] = xay[j][1];
                xay[j][0] = xay[j + 1][0];
                xay[j][1] = xay[j + 1][1];
                xay[j + 1][0] = l[0];
                xay[j + 1][1] = l[1];

            }
        }
    }
    for (int i = 0; i < n; i++)
    {
        if (s >= xay[i][1] && b + a >= xay[i][0])
        {
            s-=xay[i][1];
            all+=1;
        }
    }
    cout<<all;
}
